SELECT id, user_id, title, description, file_url, file_size, file_type, category_id, download_count, like_count, status, created_at, updated_at FROM resources
status != 0
AND category_id = #{categoryId}
AND user_id = #{userId}
AND (title LIKE CONCAT('%', #{keyword}, '%') OR description LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY created_at DESC

SELECT COUNT(*)
FROM resources

    status != 0

        AND category_id = #{categoryId}


        AND user_id = #{userId}


        AND (title LIKE CONCAT('%', #{keyword}, '%') OR description LIKE CONCAT('%', #{keyword}, '%'))

mapper.update:
UPDATE resources
SET download_count = download_count + 1
WHERE id = #{id}

UPDATE resources
SET like_count = like_count + 1
WHERE id = #{id}

UPDATE resources
SET like_count = GREATEST(like_count - 1, 0)
WHERE id = #{id}

mapper.select:
SELECT r.id, r.user_id, r.title, r.description, r.file_url, r.file_size, r.file_type, r.category_id, 
       r.download_count, r.like_count, r.status, r.created_at, r.updated_at
FROM resources r


        AND (r.title LIKE CONCAT('%', #{keyword}, '%') OR r.description LIKE CONCAT('%', #{keyword}, '%'))


        AND r.category_id = #{categoryId}


        AND r.status = #{status}


ORDER BY r.created_at DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM resources r


        AND (r.title LIKE CONCAT('%', #{keyword}, '%') OR r.description LIKE CONCAT('%', #{keyword}, '%'))


        AND r.category_id = #{categoryId}


        AND r.status = #{status}
